def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a comics character into a fluent, single
    complex sentence. When a triple's subject matches the object of the previous
    triple, the clause is turned into a relative clause using "which".
    """
    if not triples:
        return ""

    # Helper to singularise simple plurals (e.g., "Americans" → "American")
    def _singular(val: str) -> str:
        if val.endswith('s') and not val.endswith('ss') and ' ' not in val:
            return val[:-1]
        return val

    # Build a phrase for a triple; optionally omit the subject (for relative clauses)
    def _verb_phrase(subject: str, predicate: str, obj: str, include_subject: bool) -> str:
        pred = predicate.lower()
        if pred == "alternativename":
            return f"{subject} is also known as {obj}" if include_subject else f"is also known as {obj}"
        if pred == "creator":
            return f"{subject} was created by {obj}" if include_subject else f"was created by {obj}"
        if pred == "fullname":
            return f"{subject}'s full name is {obj}" if include_subject else f"'s full name is {obj}"
        if pred == "foundedby":
            return f"{subject} was founded by {obj}" if include_subject else f"was founded by {obj}"
        if pred == "keyperson":
            return f"{obj} is a key person at {subject}" if include_subject else f"is a key person at {subject}"
        if pred == "city":
            return f"{subject} is located in {obj}" if include_subject else f"is located in {obj}"
        if pred == "product":
            return f"{subject} produces {obj}" if include_subject else f"produces {obj}"
        if pred == "lastaired":
            return f"The last episode of {subject} aired on {obj}" if include_subject else f"aired on {obj}"
        if pred == "starring":
            return f"{subject} stars {obj}" if include_subject else f"stars {obj}"
        if pred == "firstappearanceinfilm":
            return f"{subject} first appeared in the film {obj}" if include_subject else f"first appeared in the film {obj}"
        if pred == "voice":
            return f"{obj} provides the voice for {subject}" if include_subject else f"provides the voice for {subject}"
        if pred == "distributor":
            return f"{obj} distributed {subject}" if include_subject else f"was distributed by {obj}"
        if pred == "birthplace":
            return f"{subject} was born in {obj}" if include_subject else f"was born in {obj}"
        if pred == "nationality":
            return f"{subject} is {_singular(obj)}" if include_subject else f"is {_singular(obj)}"
        if pred == "award":
            return f"{subject} received the {obj}" if include_subject else f"received the {obj}"
        if pred == "broadcastedby":
            return f"{subject} was broadcasted by {obj}" if include_subject else f"was broadcasted by {obj}"
        if pred == "firstaired":
            return f"{subject} first aired on {obj}" if include_subject else f"first aired on {obj}"
        if pred == "series":
            return f"{subject} is part of the series {obj}" if include_subject else f"is part of the series {obj}"
        if pred == "child":
            return f"{subject} has a child named {obj}" if include_subject else f"has a child named {obj}"
        # fallback
        return f"{subject} {predicate} {obj}" if include_subject else f"{predicate} {obj}"

    phrase_parts = []
    prev_object = None
    for triple in triples:
        s, p, o = triple.subject, triple.predicate, triple.object
        o = o.strip('"\'')
        # Determine if we should use a relative clause
        if prev_object is not None and s == prev_object:
            phrase = f"which {_verb_phrase(s, p, o, include_subject=False)}"
        else:
            phrase = _verb_phrase(s, p, o, include_subject=True)
        phrase_parts.append(phrase)
        prev_object = o

    # Assemble into a single readable sentence
    if len(phrase_parts) == 1:
        return phrase_parts[0] + "."
    elif len(phrase_parts) == 2:
        return f"{phrase_parts[0]} and {phrase_parts[1]}."
    else:
        return f"{', '.join(phrase_parts[:-1])}, and {phrase_parts[-1]}."

# EVOLVE-BLOCK-END

